function compressImage(file, maxPx=1200, q=0.82) {
  return new Promise(resolve => {
    const img=new Image(), url=URL.createObjectURL(file);
    img.onload=()=>{
      URL.revokeObjectURL(url);
      let {width:w,height:h}=img;
      if(w>maxPx||h>maxPx){if(w>h){h=Math.round(h*maxPx/w);w=maxPx;}else{w=Math.round(w*maxPx/h);h=maxPx;}}
      const c=document.createElement("canvas");c.width=w;c.height=h;
      c.getContext("2d").drawImage(img,0,0,w,h);
      const dataUrl=c.toDataURL("image/jpeg",q);
      resolve({dataUrl,base64:dataUrl.split(",")[1]});
    };
    img.src=url;
  });
}

function useLS(key,init) {
  const [v,setV]=useState(()=>{try{const s=localStorage.getItem(key);return s?JSON.parse(s):init;}catch{return init;}});
  const set=useCallback(val=>{setV(val);try{localStorage.setItem(key,JSON.stringify(val));}catch{}},[key]);
  return [v,set];
}

