/* ═══════════════════════════════════════════════
   4. CONFIDENCE METER — SVG arc gauge
═══════════════════════════════════════════════ */
function ConfidenceMeter({scores}) {
  const C = useC();
  const [filled, setFilled] = useState(false);

  useEffect(()=>{ const t=setTimeout(()=>setFilled(true),400); return()=>clearTimeout(t); },[]);

  // Confidence = average of scores, higher scores = more confident
  const avg = Object.values(scores).reduce((s,v)=>s+v.score,0)/5;
  // Spread between scores — low spread = high confidence
  const spread = Math.max(...Object.values(scores).map(v=>v.score)) - Math.min(...Object.values(scores).map(v=>v.score));
  const confidence = Math.round(Math.min(100, Math.max(40, (avg*8) - (spread*3))));
  const col = confidence>=80?C.green:confidence>=60?C.gold:C.amber;

  // SVG arc: r=36, cx=50, cy=54, half circle (180deg)
  const r=36, cx=50, cy=54;
  const circ = Math.PI*r; // half circumference
  const dash = filled ? (confidence/100)*circ : 0;

  return (
    <div style={{textAlign:"center",padding:"20px 0 8px"}}>
      <svg width="100" height="60" viewBox="0 0 100 60" style={{overflow:"visible"}}>
        {/* Track */}
        <path d={`M${cx-r},${cy} A${r},${r} 0 0,1 ${cx+r},${cy}`}
          fill="none" stroke={C.line} strokeWidth="5" strokeLinecap="round"/>
        {/* Fill */}
        <path d={`M${cx-r},${cy} A${r},${r} 0 0,1 ${cx+r},${cy}`}
          fill="none" stroke={col} strokeWidth="5" strokeLinecap="round"
          strokeDasharray={`${circ}`}
          strokeDashoffset={`${circ - dash}`}
          style={{transition:"stroke-dashoffset 1.2s cubic-bezier(0.4,0,0.2,1)"}}/>
        {/* Value */}
        <text x={cx} y={cy-8} textAnchor="middle"
          style={{fontFamily:F.display,fontSize:22,fill:col}}>{confidence}%</text>
        <text x={cx} y={cy+2} textAnchor="middle"
          style={{fontFamily:F.mono,fontSize:6,fill:C.body,letterSpacing:"0.1em"}}>CONFIDENCE</text>
      </svg>
    </div>
  );
}

