function ebayUrl(cardName, grade) {
  const query = grade === "raw"
    ? `${cardName} pokemon card`
    : `${cardName} pokemon ${grade}`;
  const params = new URLSearchParams({
    _nkw: query,
    LH_Sold: "1",
    LH_Complete: "1",
    _sop: "13", // sort by most recent
  });
  return `https://www.ebay.com.au/sch/i.html?${params.toString()}`;
}

