/* ═══════════════════════════════════════════════
   BREAK-EVEN CALCULATOR
═══════════════════════════════════════════════ */
function BreakEvenCalc({market,estimatedGrade,company="PSA"}) {
  const C = useC();
  const co = GRADING_CO[company]||GRADING_CO.PSA;
  // Build fee tiers from company config
  const tiers = {
    economy:     {label:"Economy",      price:co.fees.economy,      time:"6–12 mo"},
    standard:    {label:"Standard",     price:co.fees.standard,     time:"3–6 mo"},
    express:     {label:"Express",      price:co.fees.express,      time:"5–10 days"},
    superExpress:{label:"Super Express",price:co.fees.superExpress, time:"2–5 days"},
  };
  const [paid,setPaid]=useState("");
  const [tier,setTier]=useState("economy");
  const fee=tiers[tier].price, ship=15;
  const cost=parseFloat(paid||0)+fee+ship;
  const isHigh=(estimatedGrade||"").match(/9\.5|9\+|10/);
  const isMid=(estimatedGrade||"").match(/7|8|8\.5/);
  const saleVal=isHigh?(market?.psa10Price||market?.psa9Price):isMid?market?.psa9Price:market?.rawPrice;
  const profit=saleVal?saleVal-cost:null;
  const col=profit==null?C.body:profit>0?C.green:C.red;

  return (
    <div>
      {rule}
      <Label>Break-even calculator — {co.name}</Label>
      <div style={{marginTop:16,display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
        <div>
          <div style={{fontFamily:F.mono,fontSize:9,color:C.body,letterSpacing:"0.1em",marginBottom:6}}>WHAT YOU PAID</div>
          <div style={{position:"relative"}}>
            <span style={{position:"absolute",left:10,top:"50%",transform:"translateY(-50%)",fontFamily:F.mono,fontSize:13,color:C.body}}>$</span>
            <input value={paid} onChange={e=>setPaid(e.target.value.replace(/[^0-9.]/g,""))} placeholder="0"
              style={{width:"100%",background:C.ink,border:`1px solid ${C.line}`,borderRadius:6,padding:"10px 10px 10px 24px",fontFamily:F.mono,fontSize:14,color:C.hi,outline:"none",boxSizing:"border-box"}}/>
          </div>
        </div>
        <div>
          <div style={{fontFamily:F.mono,fontSize:9,color:C.body,letterSpacing:"0.1em",marginBottom:6}}>{company} TIER</div>
          <select value={tier} onChange={e=>setTier(e.target.value)}
            style={{width:"100%",background:C.ink,border:`1px solid ${C.line}`,borderRadius:6,padding:"10px",fontFamily:F.body,fontSize:13,color:C.hi,outline:"none",boxSizing:"border-box",appearance:"none"}}>
            {Object.entries(tiers).map(([k,v])=><option key={k} value={k}>{v.label} — {fmt(v.price)}</option>)}
          </select>
        </div>
      </div>

      <div style={{marginTop:12,padding:"20px",background:C.ink,border:`1px solid ${C.line}`,borderRadius:4,textAlign:"center"}}>
        <div style={{fontFamily:F.mono,fontSize:9,color:C.body,letterSpacing:"0.12em",marginBottom:8}}>ESTIMATED PROFIT</div>
        <div style={{fontFamily:F.display,fontSize:52,color:col,lineHeight:1}}>
          {profit==null?"—":(profit>=0?"+":"")+fmt(profit)}
        </div>
        {profit!=null&&<div style={{fontFamily:F.body,fontSize:12,color:C.body,marginTop:8}}>
          {profit>50?"Strong return":profit>0?"Marginal — consider timing":profit>-30?"Near break-even":"Likely a loss at this tier"}
        </div>}
      </div>

      <div style={{marginTop:8}}>
        {Object.entries(tiers).map(([k,v])=>{
          const net=saleVal?saleVal-(parseFloat(paid)||0)-v.price-ship:null;
          return (
            <div key={k} onClick={()=>setTier(k)} style={{
              display:"flex",justifyContent:"space-between",alignItems:"center",
              padding:"10px 0",borderBottom:`1px solid ${C.line}`,cursor:"pointer",
              WebkitTapHighlightColor:"transparent"}}>
              <div>
                <span style={{fontFamily:F.body,fontSize:13,color:tier===k?C.hi:C.body,fontWeight:tier===k?600:400}}>{v.label}</span>
                <span style={{fontFamily:F.mono,fontSize:10,color:C.body,marginLeft:8}}>{v.time}</span>
              </div>
              <span style={{fontFamily:F.mono,fontSize:13,color:net==null?C.body:net>0?C.green:C.red}}>
                {net==null?fmt(v.price):(net>=0?"+":"")+fmt(net)}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

