/* ═══════════════════════════════════════════════
   SHARE
═══════════════════════════════════════════════ */
function ShareResult({result,overallScore,frontImage}) {
  const C = useC();
  const [copied,setCopied]=useState(false);
  const [generating,setGenerating]=useState(false);
  const verdictColour = result.verdict==="Worth Grading"?"#2E7D4F":result.verdict==="Maybe"?"#C9A84C":"#8B2020";
  const text=`${result.cardName} (${result.set}) — ${result.verdict}\nEst. PSA ${result.estimatedPSAGrade} · Overall ${overallScore}/10\n\nScanned with TCGscout — tcgscout.com`;

  const downloadImage = async () => {
    setGenerating(true);
    try {
      const canvas = document.createElement("canvas");
      canvas.width = 800; canvas.height = 420;
      const ctx = canvas.getContext("2d");

      // Background
      ctx.fillStyle = "#000000";
      ctx.fillRect(0,0,800,420);

      // Gold top bar
      ctx.fillStyle = verdictColour;
      ctx.fillRect(0,0,800,4);

      // Card thumbnail on left
      if(frontImage) {
        const img = new Image();
        await new Promise(resolve=>{img.onload=resolve;img.src=frontImage;});
        const th=340, tw=Math.round(th*63/88);
        ctx.save();
        ctx.beginPath();
        ctx.roundRect(40,40,tw,th,6);
        ctx.clip();
        ctx.drawImage(img,40,40,tw,th);
        ctx.restore();
      }

      // Right side content
      const lx = frontImage ? 310 : 40;

      // Brand
      ctx.font="500 13px 'JetBrains Mono', monospace";
      ctx.fillStyle="#909090";
      ctx.letterSpacing="2px";
      ctx.fillText("TCGSCOUT",lx,60);

      // Card name
      ctx.font="700 28px 'Inter', sans-serif";
      ctx.fillStyle="#FFFFFF";
      ctx.fillText(result.cardName,lx,110);

      // Set
      ctx.font="400 14px 'Inter', sans-serif";
      ctx.fillStyle="#909090";
      ctx.fillText(result.set,lx,135);

      // Verdict
      ctx.font="700 18px 'Inter', sans-serif";
      ctx.fillStyle=verdictColour;
      ctx.fillText(result.verdict.toUpperCase(),lx,185);

      // Divider
      ctx.fillStyle="#242424";
      ctx.fillRect(lx,200,460,1);

      // Stats row
      const stats=[["EST. GRADE",result.estimatedPSAGrade],["OVERALL",`${overallScore}/10`],["CENTERING",`${result.scores.centering.score}/10`]];
      stats.forEach(([label,val],i)=>{
        const sx=lx+(i*155);
        ctx.font="500 10px 'JetBrains Mono', monospace";
        ctx.fillStyle="#909090";
        ctx.fillText(label,sx,228);
        ctx.font="600 24px 'Inter', sans-serif";
        ctx.fillStyle="#FFFFFF";
        ctx.fillText(val,sx,258);
      });

      // Divider
      ctx.fillStyle="#242424";
      ctx.fillRect(lx,275,460,1);

      // Score bars
      const criteria=[["Centering",result.scores.centering.score],["Corners",result.scores.corners.score],["Edges",result.scores.edges.score],["Surface",result.scores.surface.score]];
      criteria.forEach(([name,score],i)=>{
        const by=300+(i*25);
        ctx.font="400 11px 'Inter', sans-serif";
        ctx.fillStyle="#909090";
        ctx.fillText(name,lx,by);
        // Track
        ctx.fillStyle="#242424";
        ctx.beginPath();ctx.roundRect(lx+90,by-10,280,6,3);ctx.fill();
        // Fill
        ctx.fillStyle=score>=8?"#2E7D4F":score>=6?"#C9A84C":"#8B2020";
        ctx.beginPath();ctx.roundRect(lx+90,by-10,Math.round(280*score/10),6,3);ctx.fill();
        // Number
        ctx.font="500 11px 'JetBrains Mono', monospace";
        ctx.fillStyle="#FFFFFF";
        ctx.fillText(`${score}`,lx+380,by);
      });

      // Footer
      ctx.font="400 11px 'JetBrains Mono', monospace";
      ctx.fillStyle="#3A3A3A";
      ctx.fillText("tcgscout.com · Free AI card grading",lx,400);

      // Download
      const link=document.createElement("a");
      link.download=`tcgscout-${result.cardName.replace(/\s+/g,"-").toLowerCase()}.png`;
      link.href=canvas.toDataURL("image/png");
      link.click();
    } catch(e){console.error(e);}
    finally{setGenerating(false);}
  };

  return (
    <div>
      {rule}
      <Label>Share</Label>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginTop:14}}>
        <GhostBtn onClick={()=>{navigator.clipboard?.writeText(text).then(()=>{setCopied(true);setTimeout(()=>setCopied(false),2e3)});}}>
          {copied?"Copied":"Copy text"}
        </GhostBtn>
        <GhostBtn onClick={downloadImage} style={{opacity:generating?0.5:1}}>
          {generating?"Generating...":"Save image"}
        </GhostBtn>
        <GhostBtn onClick={()=>window.open(`https://twitter.com/intent/tweet?text=${encodeURIComponent(text)}`,"_blank")}>
          Share on X
        </GhostBtn>
      </div>
    </div>
  );
}

