function ChecklistPage({onNavigate}) {
  const C = useC();
  const [checked,setChecked]=useLS("tcg_checklist",{});
  const [activeSection,setActiveSection]=useState(null);
  useEffect(()=>window.scrollTo(0,0),[]);

  const toggle = id => setChecked(prev=>({...prev,[id]:!prev[id]}));
  const clearAll = () => setChecked({});

  const totalItems = CHECKLIST_SECTIONS.reduce((s,sec)=>s+sec.items.length,0);
  const checkedCount = Object.values(checked).filter(Boolean).length;
  const pct = Math.round(checkedCount/totalItems*100);

  return (
    <div style={{maxWidth:600,margin:"0 auto",padding:"28px 20px 100px"}}>

      {/* Header */}
      <button onClick={()=>onNavigate("articles")} style={{background:"transparent",border:"none",fontFamily:F.mono,fontSize:9,color:C.body,cursor:"pointer",padding:0,marginBottom:24,letterSpacing:"0.12em",WebkitTapHighlightColor:"transparent"}}>
        ← GUIDES
      </button>
      <div style={{marginBottom:24}}>
        <span style={{fontFamily:F.mono,fontSize:10,color:C.gold,letterSpacing:"0.12em",textTransform:"uppercase"}}>Pre-submission</span>
        <h1 style={{fontFamily:F.body,fontSize:24,fontWeight:700,color:C.hi,margin:"10px 0 10px",lineHeight:1.2}}>Grading checklist</h1>
        <p style={{fontFamily:F.body,fontSize:14,color:C.body,margin:0,lineHeight:1.7}}>
          Work through every step before sending a card to PSA. Saved automatically as you go.
        </p>
      </div>

      {/* Progress bar */}
      <div style={{marginBottom:28}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",marginBottom:8}}>
          <span style={{fontFamily:F.mono,fontSize:10,color:C.body,letterSpacing:"0.08em"}}>{checkedCount} OF {totalItems} COMPLETE</span>
          <span style={{fontFamily:F.display,fontSize:28,color:pct===100?C.green:C.gold,lineHeight:1}}>{pct}%</span>
        </div>
        <div style={{height:2,background:C.line,borderRadius:1,overflow:"hidden"}}>
          <div style={{height:"100%",width:`${pct}%`,background:pct===100?C.green:C.gold,borderRadius:1,transition:"width 0.4s cubic-bezier(0.4,0,0.2,1)"}}/>
        </div>
        {pct===100&&(
          <div style={{marginTop:12,padding:"12px 14px",background:`${C.green}18`,border:`1px solid ${C.green}40`,borderRadius:4,fontFamily:F.body,fontSize:13,color:C.green,lineHeight:1.5}}>
            All checks complete. This card is ready for PSA submission.
          </div>
        )}
      </div>

      {/* Sections */}
      {CHECKLIST_SECTIONS.map((section,si)=>{
        const sectionChecked=section.items.filter(i=>checked[i.id]).length;
        const sectionDone=sectionChecked===section.items.length;
        const isOpen=activeSection===si||activeSection===null;

        return (
          <div key={si} style={{marginBottom:4}}>
            {/* Section header */}
            <div onClick={()=>setActiveSection(activeSection===si?null:si)}
              style={{display:"flex",alignItems:"center",gap:12,padding:"13px 0",borderBottom:`1px solid ${C.line}`,cursor:"pointer",WebkitTapHighlightColor:"transparent"}}>
              <div style={{width:20,height:20,borderRadius:3,border:`1.5px solid ${sectionDone?C.green:C.line}`,background:sectionDone?C.green:"transparent",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,transition:"all 0.2s"}}>
                {sectionDone&&<span style={{color:C.bg,fontSize:11,fontWeight:700,lineHeight:1}}>✓</span>}
              </div>
              <span style={{flex:1,fontFamily:F.body,fontSize:14,fontWeight:600,color:sectionDone?C.body:C.hi}}>{section.heading}</span>
              <span style={{fontFamily:F.mono,fontSize:10,color:C.body,flexShrink:0}}>{sectionChecked}/{section.items.length}</span>
              <span style={{color:C.body,fontSize:14,flexShrink:0,transform:activeSection===si?"rotate(45deg)":"none",transition:"transform 0.2s",lineHeight:1}}>+</span>
            </div>

            {/* Items */}
            {activeSection===si&&(
              <div style={{paddingBottom:8}}>
                {section.items.map(item=>(
                  <div key={item.id} onClick={()=>toggle(item.id)}
                    style={{display:"flex",alignItems:"flex-start",gap:12,padding:"11px 0",borderBottom:`1px solid ${C.line}`,cursor:"pointer",WebkitTapHighlightColor:"transparent"}}>
                    <div style={{
                      width:20,height:20,borderRadius:3,flexShrink:0,marginTop:1,
                      border:`1.5px solid ${checked[item.id]?C.green:C.line}`,
                      background:checked[item.id]?C.green:"transparent",
                      display:"flex",alignItems:"center",justifyContent:"center",
                      transition:"all 0.15s"
                    }}>
                      {checked[item.id]&&<span style={{color:C.bg,fontSize:11,fontWeight:700,lineHeight:1}}>✓</span>}
                    </div>
                    <span style={{fontFamily:F.body,fontSize:13,color:checked[item.id]?C.body:C.hi,lineHeight:1.55,textDecoration:checked[item.id]?"line-through":"none",opacity:checked[item.id]?0.5:1,transition:"all 0.15s"}}>{item.text}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        );
      })}

      {/* Actions */}
      <div style={{marginTop:24,display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
        <GhostBtn onClick={clearAll}>Reset all</GhostBtn>
        <PrimaryBtn onClick={()=>onNavigate("scanner")} style={{width:"auto"}}>Scan card</PrimaryBtn>
      </div>

      <p style={{fontFamily:F.mono,fontSize:9,color:C.body,textAlign:"center",marginTop:16,letterSpacing:"0.08em",opacity:0.6}}>
        PROGRESS SAVED AUTOMATICALLY
      </p>
    </div>
  );
}

